#include "nxdbmgr.h"

/**
 * Protected stock images of the image library. Payloads are base64-encoded
 * PNG files from the images/ source directory. Seeded by SeedStockImages()
 * at database initialization; also used by upgrade procedures to backfill
 * missing stock image data (see H_UpgradeFromV12 in upgrade_v62.cpp).
 */
static const struct
{
   const wchar_t *guid;
   const wchar_t *name;
   const wchar_t *category;
   const char *mimetype;
   const char *data;
} s_stockImages[] =
{
   // BEGIN GENERATED STOCK IMAGE DATA (tools/regen_stock_images.py)
   // Service
   { L"092e4b35-4e7c-42df-b9b7-d5805bfac64e", L"Service", L"Network Objects", "image/png",
     "" },
   // ATM
   { L"1ddb76a3-a05f-4a42-acda-22021768feaf", L"ATM", L"Network Objects", "image/png",
     "" },
   // Unknown
   { L"7cd999e9-fbe0-45c3-a695-f84523b3a50c", L"Unknown", L"Network Objects", "image/png",
     "" },
   // Node
   { L"904e7291-ee3f-41b7-8132-2bd29288ecc8", L"Node", L"Network Objects", "image/png",
     "" },
   // HSM
   { L"b314cf44-b2aa-478e-b23a-73bc5bb9a624", L"HSM", L"Network Objects", "image/png",
     "" },
   // Server
   { L"ba6ab507-f62d-4b8f-824c-ca9d46f22375", L"Server", L"Network Objects", "image/png",
     "" },
   // Router
   { L"bacde727-b183-4e6c-8dca-ab024c88b999", L"Router", L"Network Objects", "image/png",
     "" },
   // Printer
   { L"f5214d16-1ab1-4577-bb21-063cfd45d7af", L"Printer", L"Network Objects", "image/png",
     "" },
   // Switch
   { L"f9105c54-8dcf-483a-b387-b4587dfd3cba", L"Switch", L"Network Objects", "image/png",
     "" },
   // END GENERATED STOCK IMAGE DATA
};

/**
 * Find embedded base64-encoded payload for a stock image by GUID.
 * Returns nullptr if the GUID is not one of the known stock images.
 */
const char *FindStockImageData(const wchar_t *guid)
{
   for (size_t i = 0; i < sizeof(s_stockImages) / sizeof(s_stockImages[0]); i++)
   {
      if (!wcsicmp(guid, s_stockImages[i].guid))
         return s_stockImages[i].data;
   }
   return nullptr;
}

/**
 * Seed stock image library images at database initialization
 */
bool SeedStockImages()
{
   DB_STATEMENT hStmt = DBPrepare(g_dbHandle, L"INSERT INTO images (guid,name,category,mimetype,protected,image_data) VALUES (?,?,?,?,1,?)");
   if (hStmt == nullptr)
      return false;

   bool success = true;
   for (size_t i = 0; (i < sizeof(s_stockImages) / sizeof(s_stockImages[0])) && success; i++)
   {
      char *data = nullptr;
      size_t size = 0;
      if (!base64_decode_alloc(s_stockImages[i].data, strlen(s_stockImages[i].data), &data, &size) || (data == nullptr))
      {
         WriteToTerminalEx(L"Cannot decode embedded image data for stock image \"%s\"\n", s_stockImages[i].name);
         success = false;
         break;
      }

      DBBind(hStmt, 1, DB_SQLTYPE_VARCHAR, s_stockImages[i].guid, DB_BIND_STATIC);
      DBBind(hStmt, 2, DB_SQLTYPE_VARCHAR, s_stockImages[i].name, DB_BIND_STATIC);
      DBBind(hStmt, 3, DB_SQLTYPE_VARCHAR, s_stockImages[i].category, DB_BIND_STATIC);
      DBBind(hStmt, 4, DB_SQLTYPE_VARCHAR, DB_CTYPE_UTF8_STRING, s_stockImages[i].mimetype, DB_BIND_STATIC);
      DBBind(hStmt, 5, DB_SQLTYPE_TEXT, reinterpret_cast<BYTE*>(data), size, DB_BIND_DYNAMIC);
      success = SQLExecute(hStmt);
   }

   DBFreeStatement(hStmt);
   return success;
}
